        queue<int> q;

        // Loop through all vertices
        for (int i = 0; i < V; i++) {
            // If in-degree is zero, add to queue
            if (indegree[i] == 0) {
                q.push(i);
            }
        }

        // Vector to store the topological order
        vector<int> topo;

        // Process until queue is empty
        while (!q.empty()) {
            // Get the front vertex from the queue
            int node = q.front();
