            // Add it to the topological order
            topo.push_back(node);

            // Reduce in-degree of its adjacent vertices
            for (auto it : adj[node]) {
                indegree[it]--;
                // If in-degree becomes zero, push it into queue
                if (indegree[it] == 0) {
