            topo[idx++] = node;

            // Loop through adjacent vertices of the current node
            for (int it : adj.get(node)) {
                // Reduce in-degree of connected vertex
                indegree[it]--;
                // If in-degree becomes zero, push it to queue
                if (indegree[it] == 0) {
                    q.add(it);
                }
            }
        }

        // Return the topological ordering
